insert into public.site_content (key,value,label,page,section,kind,sort) values ('home.calm-comfortable-stress-free.from-planning-your-session-to-delivering','From planning your session to delivering your final gallery, I’ll guide you every step of the way. Sessions are designed to be calm, comfortable, and stress-free — especially for young families and first-time parents.','Paragraph','home','Calm, comfortable & stress-free','textarea',28) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('home.calm-comfortable-stress-free.with-gentle-direction-and-a-focus-on-nat','With gentle direction and a focus on natural moments, you can relax and enjoy time together while I document the connection, emotion, and details you’ll want to remember for years to come.','Paragraph 2','home','Calm, comfortable & stress-free','textarea',29) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('home.hi-i-m-susana.i-m-a-roswell-ga-photographer-specializi','I’m a Roswell, GA photographer specializing in family, newborn, maternity, milestone, and couples photography. My approach is relaxed and natural, focusing on genuine connection and creating light, airy images that feel timeless and true to your family.','Paragraph','home','Hi, I’m Susana','textarea',30) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('home.hi-i-m-susana.whether-you-re-welcoming-a-new-baby-cele','Whether you’re welcoming a new baby, celebrating a milestone, or simply wanting to remember this season as it is, I’m here to document your story in a way that feels effortless and meaningful.','Paragraph 2','home','Hi, I’m Susana','textarea',31) on conflict (key) do nothing;
