insert into public.site_content (key,value,label,page,section,kind,sort) values ('about.meta.description','Meet Susana Stethers — a Roswell, Georgia family photographer creating relaxed, kid-friendly sessions and light, airy images that feel natural and timeless.','Google description (aim for 150–160 characters)','about','SEO','textarea',38) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('about.page.hi-i-m-susana-the-photographer-behind-th','Hi, I’m Susana — the photographer behind the camera.','Main heading','about','Page','text',39) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('about.page.i-m-a-roswell-ga-family-photographer-spe','I’m a Roswell, GA family photographer specializing in newborn, family, maternity, milestone, and couples photography. I’m drawn to the beauty in everyday moments — soft light, genuine connection, and the small details that make each season of life meaningful.','Paragraph','about','Page','textarea',40) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('about.page.as-a-mom-myself-i-understand-how-fleetin','As a mom myself, I understand how fleeting these moments are and how quickly life changes. That perspective shapes the way I approach every session. My goal is to create a relaxed, comfortable experience where your family can slow down, be present, and simply enjoy time together.','Paragraph 2','about','Page','textarea',41) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('about.page.my-sessions-are-kid-friendly-and-guided-','My sessions are kid-friendly and guided in a natural way, making space for both quiet moments and playful energy. I love working with children of all personalities — from shy little ones who need time to warm up to high-energy kids who want to run, explore, and be themselves. I’ll happily get on the floor, follow their lead, and gently guide you so nothing ever feels awkward or forced.','Paragraph 3','about','Page','textarea',42) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('about.page.outside-of-photography-i-m-inspired-by-f','Outside of photography, I’m inspired by flowers, beautiful spaces, travel, and event planning — anything that celebrates creativity and thoughtful details. That love for beauty and intention carries into my work, where I focus on creating light, airy images that feel natural, warm, and timeless.','Paragraph 4','about','Page','textarea',43) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('about.page.my-goal-is-to-preserve-your-family-s-mem','My goal is to preserve your family’s memories in a way that feels honest and enduring — images you’ll return to years from now and remember exactly how this season of life felt.','Paragraph 5','about','Page','textarea',44) on conflict (key) do nothing;
