insert into public.site_content (key,value,label,page,section,kind,sort) values ('experience.page.once-you-book-i-ll-guide-you-through-sim','Once you book, I’ll guide you through simple preparation so you feel ready and relaxed. This includes outfit suggestions, location guidance, and help choosing the best timing for your session.','Paragraph','experience','Page','textarea',60) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('experience.page.sessions-are-calm-playful-and-natural-i-','Sessions are calm, playful, and natural. I’ll offer gentle direction while allowing space for authentic moments to unfold. You’ll never be left wondering what to do, and there’s no pressure for perfection — just connection.','Paragraph 2','experience','Page','textarea',61) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('experience.page.you-ll-receive-a-thoughtfully-curated-on','You’ll receive a thoughtfully curated online gallery filled with images that reflect your family just as they are in this season — honest, warm, and timeless photographs you’ll cherish for years to come.','Paragraph 3','experience','Page','textarea',62) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('experience.frequently-asked-questions.that-s-completely-normal-and-welcome-i-l','That’s completely normal — and welcome! I’ll get on their level, follow their lead, and get silly when needed. The most meaningful images come from real connection, not practiced smiles.','FAQ answer','experience','Frequently asked questions','textarea',63) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('experience.frequently-asked-questions.sessions-can-take-place-outdoors-around-','Sessions can take place outdoors around Roswell and the surrounding areas, in the comfort of your home, or in a studio. Studio sessions are available for an additional rental fee, and I’ll help you choose the setting that best fits your vision.','FAQ answer 2','experience','Frequently asked questions','textarea',64) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('experience.frequently-asked-questions.after-booking-you-ll-receive-style-guida','After booking, you’ll receive style guidance with outfit suggestions that photograph beautifully in soft, natural light. Comfort always comes first, especially for little ones.','FAQ answer 3','experience','Frequently asked questions','textarea',65) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('experience.frequently-asked-questions.reach-out-during-pregnancy-whenever-you-','Reach out during pregnancy whenever you feel ready so we can reserve a flexible window around your due date. Lifestyle newborn sessions are often photographed during the first few weeks, but there is no strict age cutoff — we’ll choose timing that feels comfortable for your family.','FAQ answer 4','experience','Frequently asked questions','textarea',66) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('experience.frequently-asked-questions.your-thoughtfully-curated-online-gallery','Your thoughtfully curated online gallery is delivered within two weeks of your session.','FAQ answer 5','experience','Frequently asked questions','text',67) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('experience.page.my-sessions-are-designed-to-feel-easy-co','My sessions are designed to feel easy, comfortable, and enjoyable — especially for little ones. From the very beginning, my goal is to create a relaxed experience where your family feels at ease and free to be yourselves.','Paragraph 4','experience','Page','textarea',68) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('experience.page.i-take-the-time-to-connect-with-your-chi','I take the time to connect with your children, meet them where they are, and help them feel safe and confident in front of the camera. Whether your child is shy and needs a few minutes to warm up or full of energy and ready to explore, I embrace it all.','Paragraph 5','experience','Page','textarea',69) on conflict (key) do nothing;
insert into public.site_content (key,value,label,page,section,kind,sort) values ('experience.page.i-ll-get-on-their-level-follow-their-lea','I’ll get on their level, follow their lead, and get silly when needed — while gently guiding you so nothing ever feels awkward or forced. You don’t need perfectly behaved kids or practiced smiles. The most meaningful images come from real connection, and that starts with everyone feeling comfortable.','Paragraph 6','experience','Page','textarea',70) on conflict (key) do nothing;
